        }
        length = l;
        _array = [&]() { vector<decay_t<decltype([&](int _i) { return VERTICAL_IDENTITY; }(0))>> _v; _v.reserve(length * 2); for (int _i = 0; _i < length * 2; _i++) _v.push_back(VERTICAL_IDENTITY); return _v; }();
    }

    auto update(int index, Verval newVal) {
        auto node = index + length;
        _array[node] = newVal;
        node = &(node >> 1);
        while (node > 0) {
            _array[node] = _array[2 * node] * _array[2 * node + 1];
            node = &(node >> 1);
        }
    }

    auto longest() {
        return _array[1].longest;
    }

    auto posAnswer() {
        return max(_array[1].longestToUse, _array[1].posAnswer);
    }

};

